SET NAMES utf8mb4;
SET time_zone = '+00:00';
CREATE TABLE IF NOT EXISTS admins (id INT UNSIGNED NOT NULL AUTO_INCREMENT,name VARCHAR(120) NOT NULL,email VARCHAR(190) NOT NULL,password_hash VARCHAR(255) NOT NULL,role ENUM('admin','editor') NOT NULL DEFAULT 'admin',created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY admins_email_unique(email)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS articles (id INT UNSIGNED NOT NULL AUTO_INCREMENT,title VARCHAR(255) NOT NULL,slug VARCHAR(255) NOT NULL,excerpt TEXT NULL,content LONGTEXT NOT NULL,featured_image_url TEXT NULL,featured_image_alt VARCHAR(255) NULL,category VARCHAR(120) NOT NULL,language ENUM('en','hi','te') NOT NULL DEFAULT 'en',author VARCHAR(120) NULL,status ENUM('draft','published') NOT NULL DEFAULT 'draft',seo_title VARCHAR(255) NULL,seo_description TEXT NULL,source_url TEXT NULL,created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,published_at DATETIME NULL,PRIMARY KEY(id),UNIQUE KEY articles_slug_unique(slug),KEY articles_status_idx(status),KEY articles_language_idx(language),KEY articles_category_idx(category),KEY articles_published_at_idx(published_at),KEY articles_public_listing_idx(status,language,category,published_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS subscribers (id INT UNSIGNED NOT NULL AUTO_INCREMENT,name VARCHAR(120) NULL,email VARCHAR(190) NOT NULL,language ENUM('en','hi','te') NOT NULL DEFAULT 'en',status ENUM('active','unsubscribed') NOT NULL DEFAULT 'active',subscribed_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY subscribers_email_unique(email),KEY subscribers_status_idx(status),KEY subscribers_language_idx(language),KEY subscribers_status_language_idx(status,language)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
